async (params, browser) => {
  // Open page
  await browser.open('https://app.todoist.com/app/inbox')

  // Wait for content
  await browser.waitForSelector('.task_list_item, [class*="task_list_item"], [data-testid="task"]', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const tasks = Array.from(document.querySelectorAll('.task_list_item, [class*="task_list_item"], [data-testid="task"]')).slice(0,50).map(el => { const title = el.querySelector('.task_content, [class*="task_content"], [data-testid="task-name"]')?.textContent?.trim()||''; const due = el.querySelector('.date, [class*="due_date"], time')?.textContent?.trim()||''; const priority = el.querySelector('[class*="priority"]')?.className?.match(/priority_(\d)/)?.[1]||''; const labels = Array.from(el.querySelectorAll('[class*="label"], .tag')).map(l=>l.textContent.trim()); return { title, due_date: due, priority, labels }; }).filter(t=>t.title); return { project: 'Inbox', tasks }`)

  return page_data
}
